const canvas = document.getElementById('board');
const ctx = canvas.getContext('2d');

// Resize canvas to fill the window
function resize() {
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
}
window.addEventListener('resize', resize);
resize();

// Setup WebSocket connection
const socket = new WebSocket('ws://localhost:8080');

// Store drawing state
let drawing = false;
let lastX = 0;
let lastY = 0;

// Draw line on our canvas
function drawLine(fromX, fromY, toX, toY, color = 'black', lineWidth = 2) {
  ctx.strokeStyle = color;
  ctx.lineWidth = lineWidth;
  ctx.lineCap = 'round';
  ctx.beginPath();
  ctx.moveTo(fromX, fromY);
  ctx.lineTo(toX, toY);
  ctx.stroke();
  ctx.closePath();
}

// Mouse events for drawing
canvas.addEventListener('mousedown', e => {
  drawing = true;
  lastX = e.clientX;
  lastY = e.clientY;
});

canvas.addEventListener('mouseup', e => {
  drawing = false;
});

canvas.addEventListener('mousemove', e => {
  if (!drawing) return;
  const currentX = e.clientX;
  const currentY = e.clientY;

  // Draw locally
  drawLine(lastX, lastY, currentX, currentY);

  // Send the line data to server
  const message = JSON.stringify({ fromX: lastX, fromY: lastY, toX: currentX, toY: currentY });
  socket.send(message);

  lastX = currentX;
  lastY = currentY;
});

// Listen for messages from server
socket.addEventListener('message', event => {
  const data = JSON.parse(event.data);
  // Draw lines from other users
  drawLine(data.fromX, data.fromY, data.toX, data.toY, 'blue');
});

